const envelope = $input.first().json || {};
const payload = envelope.payload || {};

const trim = (value) => String(value || '').trim();
const candidateUrls = Array.isArray(payload.candidate_urls)
  ? payload.candidate_urls.map((value) => trim(value)).filter(Boolean)
  : [];
const siteBaseUrl = trim(payload.site_url || $env.SITE_URL || $env.SIMONE_WEB_BASE_URL || $env.NEXT_PUBLIC_SITE_URL || '').replace(/\/$/, '');
const callbackPath = trim(payload.callback_path || '/api/admin/channels/tiktok/connect/browser-metadata/callback');
const callbackUrl = trim(payload.callback_url || (siteBaseUrl ? `${siteBaseUrl}${callbackPath}` : ''));
const rawRunnerUrl = trim(
  payload.browser_runner_url ||
  $env.TIKTOK_BROWSER_METADATA_RUNNER_URL ||
  $env.BROWSER_RUNNER_WEBHOOK_URL ||
  (siteBaseUrl ? `${siteBaseUrl}/api/automation/tiktok-shop/browser-metadata` : '')
);
const runnerRequestUrl = rawRunnerUrl || '';
const callbackSecret = trim(
  $env.TIKTOK_SHOP_CALLBACK_SECRET ||
  $env.N8N_SHARED_SECRET ||
  $env.SUPPLIER_WEBHOOK_SECRET ||
  ''
);
const internalToken = trim($env.TIKTOK_BROWSER_RUNNER_TOKEN || callbackSecret);

return [{
  json: {
    eventType: trim(envelope.event_type),
    channel: trim(payload.channel || 'tiktok'),
    stateToken: trim(payload.state_token),
    browserSessionRef: trim(payload.browser_session_ref),
    targetUrl: trim(payload.target_url || candidateUrls[0] || ''),
    candidateUrls,
    callbackPath,
    callbackUrl,
    callbackSecret,
    internalToken,
    browserRunnerUrl: rawRunnerUrl,
    runnerRequestUrl,
    browserRecipe: payload.browser_recipe || {},
    requestPayload: payload.request_payload || {},
    runnerConfigured: Boolean(runnerRequestUrl && callbackUrl && callbackSecret && internalToken)
  }
}];

const request = $node['Browser-Auftrag normalisieren'].json || {};
const response = $input.first().json || {};
const crypto = require('crypto');

const trim = (value) => String(value || '').trim();
const availableShops = Array.isArray(response.available_shops)
  ? response.available_shops
  : Array.isArray(response.shops)
    ? response.shops
    : [];
const callbackBody = {
  channel: request.channel,
  state_token: request.stateToken,
  merchant_id: trim(response.merchant_id || response.seller_id),
  seller_id: trim(response.seller_id || response.merchant_id),
  shop_id: trim(response.shop_id),
  shop_cipher: trim(response.shop_cipher || response.third_shop_id),
  third_shop_id: trim(response.third_shop_id || response.shop_cipher),
  shop_name: trim(response.shop_name),
  shop_region: trim(response.shop_region),
  browser_session_ref: trim(response.browser_session_ref || request.browserSessionRef),
  source_url: trim(response.source_url || response.current_url || request.targetUrl),
  available_shops: availableShops,
  status: trim(response.status || 'completed') || 'completed'
};

const serializedBody = JSON.stringify(callbackBody);
const signature = request.callbackSecret
  ? `sha256=${crypto.createHmac('sha256', request.callbackSecret).update(serializedBody).digest('hex')}`
  : '';

return [{
  json: {
    callbackUrl: request.callbackUrl,
    callbackBody,
    serializedBody,
    signature,
    metadataFound: Boolean(callbackBody.merchant_id || callbackBody.shop_id || callbackBody.shop_cipher || availableShops.length)
  }
}];
